starterCode.css:
body {
  font-family: system-ui, sans-serif;
  padding: 24px;
}

.gallery {
  display: grid;
  gap: 16px;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
}

figure {
  margin: 0;
  background: #f6f7f9;
  padding: 12px;
  border-radius: 12px;
}

figure img {
  width: 100%;
  height: 120px;
  object-fit: cover;
  border-radius: 8px;
}
